@preconcurrency
    open func adapt(_ urlRequest: URLRequest, for session: Session, completion: @escaping @Sendable (Result<URLRequest, any Error>) -> Void) {
        adapt(urlRequest, for: session, using: adapters, completion: completion)
    }

    private func adapt(_ urlRequest: URLRequest,
                       for session: Session,
                       using adapters: [any RequestAdapter],
                       completion: @escaping @Sendable (Result<URLRequest, any Error>) -> Void) {
        var pendingAdapters = adapters

        guard !pendingAdapters.isEmpty else { completion(.success(urlRequest)); return }

        let adapter = pendingAdapters.removeFirst()

        adapter.adapt(urlRequest, for: session) { [pendingAdapters] result in
            switch result {
            case let .success(urlRequest):
                self.adapt(urlRequest, for: session, using: pendingAdapters, completion: completion)
            case .failure:
                completion(result)
            }
        }
    }

public func serialize(request: URLRequest?, response: HTTPURLResponse?, data: Data?, error: (any Error)?) throws -> String {
    guard error == nil else { throw error! }

    guard var data, !data.isEmpty else {
        guard emptyResponseAllowed(forRequest: request, response: response) else {
            throw AFError.responseSerializationFailed(reason: .inputDataNilOrZeroLength)
        }

        return ""
    }

    data = try dataPreprocessor.preprocess(data)

    var convertedEncoding = encoding

    if let encodingName = response?.textEncodingName, convertedEncoding == nil {
        convertedEncoding = String.Encoding(ianaCharsetName: encodingName)
    }

    let actualEncoding = convertedEncoding ?? .isoLatin1

    guard let string = String(data: data, encoding: actualEncoding) else {
        throw AFError.responseSerializationFailed(reason: .stringSerializationFailed(encoding: actualEncoding))
    }

    return string
}

public func serialize(request: URLRequest?, response: HTTPURLResponse?, data: Data?, error: (any Error)?) throws -> T {
    guard error == nil else { throw error! }

    guard var data, !data.isEmpty else {
        guard emptyResponseAllowed(forRequest: request, response: response) else {
            throw AFError.responseSerializationFailed(reason: .inputDataNilOrZeroLength)
        }

        guard let emptyResponseType = T.self as? any EmptyResponse.Type, let emptyValue = emptyResponseType.emptyValue() as? T else {
            throw AFError.responseSerializationFailed(reason: .invalidEmptyResponse(type: "\(T.self)"))
        }

        return emptyValue
    }

    data = try dataPreprocessor.preprocess(data)

    do {
        return try decoder.decode(T.self, from: data)
    } catch {
        throw AFError.responseSerializationFailed(reason: .decodingFailed(error: error))
    }
}

public func encode(_ urlRequest: any URLRequestConvertible, with parameters: Parameters?) throws -> URLRequest {
    var urlRequest = try urlRequest.asURLRequest()

    guard let parameters else { return urlRequest }

    guard JSONSerialization.isValidJSONObject(parameters) else {
        throw AFError.parameterEncodingFailed(reason: .jsonEncodingFailed(error: Error.invalidJSONObject))
    }

    do {
        let data = try JSONSerialization.data(withJSONObject: parameters, options: options)

        if urlRequest.headers["Content-Type"] == nil {
            urlRequest.headers.update(.contentType("application/json"))
        }

        urlRequest.httpBody = data
    } catch {
        throw AFError.parameterEncodingFailed(reason: .jsonEncodingFailed(error: error))
    }

    return urlRequest
}

@inlinable
    internal mutating func _resizeAndFlatten(newCapacity: Int) {
        var newBacking: ContiguousArray<Element?> = []
        precondition(newCapacity > 0, "Can't change capacity to \(newCapacity)")
        assert(newCapacity % 2 == 0)
        assert(newCapacity > self.capacity)

        newBacking.reserveCapacity(newCapacity)

        if self.tailBackingIndex >= self.headBackingIndex {
            newBacking.append(contentsOf: self._buffer[self.headBackingIndex..<self.tailBackingIndex])
        } else {
            newBacking.append(contentsOf: self._buffer[self.headBackingIndex...])
            newBacking.append(contentsOf: self._buffer[..<self.tailBackingIndex])
        }

        let newTailIndex = newBacking.count
        let paddingCount = newCapacity &- newTailIndex
        newBacking.append(contentsOf: repeatElement(nil, count: paddingCount))

        self.headBackingIndex = 0
        self.tailBackingIndex = newTailIndex
        self._buffer = newBacking
        assert(self.verifyInvariants())
    }

public func index(_ i: Index, offsetBy distance: Int) -> Index {
    .init(
        backingIndex: (i.backingIndex &+ distance) & self.mask,
        backingCount: self.count,
        backingIndexOfHead: self.headBackingIndex
    )
}

@inlinable
public subscript(bounds: Range<Index>) -> SubSequence {
    get {
        precondition(self.distance(from: self.startIndex, to: bounds.lowerBound) >= 0)
        precondition(self.distance(from: bounds.upperBound, to: self.endIndex) >= 0)

        var newRing = self
        newRing.headBackingIndex = bounds.lowerBound.backingIndex
        newRing.tailBackingIndex = bounds.upperBound.backingIndex
        return newRing
    }
    set {
        precondition(self.distance(from: self.startIndex, to: bounds.lowerBound) >= 0)
        precondition(self.distance(from: bounds.upperBound, to: self.endIndex) >= 0)

        self.replaceSubrange(bounds, with: newValue)
    }
}

@discardableResult public mutating func discardReadBytes() -> Bool {
    guard self._readerIndex > 0 else {
        return false
    }

    if self._readerIndex == self._writerIndex {
        // If the whole buffer was consumed we can just reset the readerIndex and writerIndex to 0 and move on.
        self._moveWriterIndex(to: 0)
        self._moveReaderIndex(to: 0)
        return true
    }

    if isKnownUniquelyReferenced(&self._storage) {
        self._storage.bytes.advanced(by: Int(self._slice.lowerBound))
            .copyMemory(
                from: self._storage.bytes.advanced(by: Int(self._slice.lowerBound + self._readerIndex)),
                byteCount: self.readableBytes
            )
        let indexShift = self._readerIndex
        self._moveReaderIndex(to: 0)
        self._moveWriterIndex(to: self._writerIndex - indexShift)
    } else {
        self._copyStorageAndRebase(extraCapacity: 0, resetIndices: true)
    }
    return true
}

enum CallbackQueueMain {
    static func currentOrAsync(_ block: @MainActor @Sendable @escaping () -> Void) {
        if Thread.isMainThread {
            MainActor.runUnsafely { block() }
        } else {
            DispatchQueue.main.async { block() }
        }
    }

    static func async(_ block: @MainActor @Sendable @escaping () -> Void) {
        DispatchQueue.main.async { block() }
    }
}

extension MainActor {
    @_unavailableFromAsync
    static func runUnsafely<T: Sendable>(_ body: @MainActor () throws -> T) rethrows -> T {
#if swift(>=5.10)
        return try MainActor.assumeIsolated(body)
#else
        dispatchPrecondition(condition: .onQueue(.main))
        return try withoutActuallyEscaping(body) { fn in
            try unsafeBitCast(fn, to: (() throws -> T).self)()
        }
#endif
    }
}

switch (type, self) {
case (.precomp, let preCompLayerModel as PreCompLayerModel):
  let preCompLayer = PreCompLayer(preCompLayer: preCompLayerModel)
  try preCompLayer.setup(context: context)
  return preCompLayer

case (.solid, let solidLayerModel as SolidLayerModel):
  return SolidLayer(solidLayerModel)

case (.shape, let shapeLayerModel as ShapeLayerModel):
  return try ShapeLayer(shapeLayer: shapeLayerModel, context: context)

case (.image, let imageLayerModel as ImageLayerModel):
  return ImageLayer(imageLayer: imageLayerModel, context: context)

case (.text, let textLayerModel as TextLayerModel):
  return try TextLayer(textLayerModel: textLayerModel, context: context)

case (.null, _):
  return TransformLayer(layerModel: self)

case (.unknown, _), (.precomp, _), (.solid, _), (.image, _), (.shape, _), (.text, _):
  return nil
}

for currentEntry in self {
  let cds = currentEntry.centralDirectoryStructure
  if currentEntry != entry {
    let entryStart = cds.effectiveRelativeOffsetOfLocalHeader
    fseeko(archiveFile, off_t(entryStart), SEEK_SET)
    let provider: Provider = { _, chunkSize -> Data in
      return try Data.readChunk(of: chunkSize, from: self.archiveFile)
    }
    let consumer: Consumer = {
      if progress?.isCancelled == true { throw ArchiveError.cancelledOperation }
      _ = try Data.write(chunk: $0, to: tempArchive.archiveFile)
      progress?.completedUnitCount += Int64($0.count)
    }
    guard currentEntry.localSize <= .max else { throw ArchiveError.invalidLocalHeaderSize }
    _ = try Data.consumePart(
      of: Int64(currentEntry.localSize),
      chunkSize: bufferSize,
      provider: provider,
      consumer: consumer
    )
    let updatedCentralDirectory = updateOffsetInCentralDirectory(
      centralDirectoryStructure: cds,
      updatedOffset: entryStart - offset
    )
    centralDirectoryData.append(updatedCentralDirectory.data)
  } else { offset = currentEntry.localSize }
}

if let dotLottieCache, let lottie = dotLottieCache.file(forKey: url.absoluteString) {
  handleResult(.success(lottie))
  return nil
} else {
  let task = session.lottieDataTask(with: url) { data, _, error in
    do {
      if let error {
        throw error
      }
      guard let data else {
        throw DotLottieError.noDataLoaded
      }
      let lottie = try DotLottieFile(data: data, filename: url.deletingPathExtension().lastPathComponent)
      DispatchQueue.main.async {
        dotLottieCache?.setFile(lottie, forKey: url.absoluteString)
        handleResult(.success(lottie))
      }
    } catch {
      DispatchQueue.main.async {
        handleResult(.failure(error))
      }
    }
  }
  task?.resume()
  return task
}

if let method = urlRequest.method, destination.encodesParametersInURL(for: method) {
    guard let url = urlRequest.url else {
        throw AFError.parameterEncodingFailed(reason: .missingURL)
    }

    if var urlComponents = URLComponents(url: url, resolvingAgainstBaseURL: false), !parameters.isEmpty {
        let percentEncodedQuery = (urlComponents.percentEncodedQuery.map { $0 + "&" } ?? "") + query(parameters)
        urlComponents.percentEncodedQuery = percentEncodedQuery
        urlRequest.url = urlComponents.url
    }
} else {
    if urlRequest.headers["Content-Type"] == nil {
        urlRequest.headers.update(.contentType("application/x-www-form-urlencoded; charset=utf-8"))
    }

    urlRequest.httpBody = Data(query(parameters).utf8)
}

switch value {
case let dictionary as [String: Any]:
    for (nestedKey, value) in dictionary {
        components += queryComponents(fromKey: "\(key)[\(nestedKey)]", value: value)
    }
case let array as [Any]:
    for (index, value) in array.enumerated() {
        components += queryComponents(fromKey: arrayEncoding.encode(key: key, atIndex: index), value: value)
    }
case let number as NSNumber:
    if number.isBool {
        components.append((escape(key), escape(boolEncoding.encode(value: number.boolValue))))
    } else {
        components.append((escape(key), escape("\(number)")))
    }
case let bool as Bool:
    components.append((escape(key), escape(boolEncoding.encode(value: bool))))
default:
    components.append((escape(key), escape("\(value)")))
}

if let credentialStorage = delegate?.sessionConfiguration.urlCredentialStorage {
    let protectionSpace = URLProtectionSpace(host: host,
                                             port: url.port ?? 0,
                                             protocol: url.scheme,
                                             realm: host,
                                             authenticationMethod: NSURLAuthenticationMethodHTTPBasic)

    if let credentials = credentialStorage.credentials(for: protectionSpace)?.values {
        for credential in credentials {
            guard let user = credential.user, let password = credential.password else { continue }
            components.append("-u \(user):\(password)")
        }
    } else {
        if let credential, let user = credential.user, let password = credential.password {
            components.append("-u \(user):\(password)")
        }
    }
}

while true {
  let nextChunk = self[currentIndex...].prefix(columns)
  if let lastLineBreak = nextChunk.lastIndex(of: "\n") {
    result.append(
      contentsOf: self[currentIndex..<lastLineBreak].split(
        separator: "\n", omittingEmptySubsequences: false))
    currentIndex = index(after: lastLineBreak)
  } else if nextChunk.endIndex == self.endIndex {
    result.append(self[currentIndex...])
    break
  } else if let lastSpace = nextChunk.lastIndex(of: " ") {
    result.append(self[currentIndex..<lastSpace])
    currentIndex = index(after: lastSpace)
  } else if let nextSpace = self[currentIndex...].firstIndex(of: " ") {
    result.append(self[currentIndex..<nextSpace])
    currentIndex = index(after: nextSpace)
  } else {
    result.append(self[currentIndex...])
    break
  }
}

