@inlinable
  public func distance(from start: Index, to end: Index) -> Int {
    guard start <= end else { return -distance(from: end, to: start) }
    guard start != end else { return 0 }
    guard end != endIndex else {
      // We add 1 here because the index before `endIndex` also has
      // `base.endIndex` as its upper bound.
      return base[start.upperBound...].count + 1
    }

    if start.upperBound <= end.lowerBound {
      // The distance between `start.lowerBound` and `start.upperBound` is
      // already known.
      //
      // start: [x|x x x x|x x x x x x x]
      //          |- - - -|> >|
      //   end: [x x x x x x x|x x x x|x]

      return windowSize + base[start.upperBound..<end.lowerBound].count
    } else {
      // start: [x|x x x x x x|x x x x x]
      //          |> > > >|
      //   end: [x x x x x|x x x x x x|x]

      return base[start.lowerBound..<end.lowerBound].count
    }
  }

switch (i.position, limit.position) {
case (.first(let i), .first(let limit)):
  return base1.index(i, offsetBy: distance, limitedBy: limit)
    .map(Index.init(first:))

case (.first(let i), .second(let limit)):
  guard
    let j = base1.index(i, offsetBy: distance, limitedBy: base1.endIndex)
  else {
    // the offset overflows the bounds of `base1` by `n - d`
    let d = base1.distance(from: i, to: base1.endIndex)
    return
      base2
      .index(base2.startIndex, offsetBy: distance - d, limitedBy: limit)
      .map(Index.init(second:))
  }
  // the offset stays within the bounds of `base1`
  return normalizeIndex(j)

case (.second, .first):
  // impossible because `limit >= i`
  fatalError()

case (.second(let i), .second(let limit)):
  return base2.index(i, offsetBy: distance, limitedBy: limit)
    .map(Index.init(second:))
}

switch (i.position, limit.position) {
case (.first(let i), .first(let limit)):
  return base1.index(i, offsetBy: -distance, limitedBy: limit)
    .map(Index.init(first:))

case (.first, .second):
  // impossible because `limit <= i`
  fatalError()

case (.second(let i), .first(let limit)):
  guard
    let j = base2.index(i, offsetBy: -distance, limitedBy: base2.startIndex)
  else {
    // the offset overflows the bounds of `base2` by `n - d`
    let d = base2.distance(from: base2.startIndex, to: i)
    return
      base1
      .index(base1.endIndex, offsetBy: -(distance - d), limitedBy: limit)
      .map(Index.init(first:))
  }
  // the offset stays within the bounds of `base2`
  return Index(second: j)

case (.second(let i), .second(let limit)):
  // `limit` is relevant, so `base1` cannot be reached
  return base2.index(i, offsetBy: -distance, limitedBy: limit)
    .map(Index.init(second:))
}

switch (index.base, limit.base, distance.isMultiple(of: 2)) {
case (.element(let index), .element(let limit), true),
  (.separator(_, next: let index), .element(let limit), false):
  return base.index(index, offsetBy: distance / 2, limitedBy: limit)
    .map { .element($0) }

case (.element(let index), .element(let limit), false),
  (.element(let index), .separator(_, next: let limit), false),
  (.separator(_, next: let index), .element(let limit), true),
  (.separator(_, next: let index), .separator(_, next: let limit), true):
  return base.index(index, offsetBy: (distance - 1) / 2, limitedBy: limit)
    .flatMap {
      guard $0 != limit else { return nil }
      let next = base.index(after: $0)
      return next == base.endIndex
        ? endIndex
        : .separator(previous: $0, next: next)
    }

case (.element(let index), .separator(_, next: let limit), true),
  (.separator(_, next: let index), .separator(_, next: let limit), false):
  return base.index(index, offsetBy: distance / 2, limitedBy: limit)
    .flatMap { $0 == limit ? nil : .element($0) }
}

if let i = indexes[countToChoose...]
        .firstIndex(where: { indexes[edge] < $0 })
      {
        indexes.swapAt(edge, i)
      } else {
        indexes.reverse(subrange: countToChoose..<indexes.endIndex)

        // Find last increasing pair below `edge`.
        // TODO: This could be indexes[..<edge].adjacentPairs().lastIndex(where: ...)
        var lastAscent = edge - 1
        while lastAscent >= 0 && indexes[lastAscent] >= indexes[lastAscent + 1]
        {
          lastAscent -= 1
        }
        if lastAscent < 0 {
          return false
        }

        // Find rightmost index less than that at `lastAscent`.
        if let i = indexes[lastAscent...]
          .lastIndex(where: { indexes[lastAscent] < $0 })
        {
          indexes.swapAt(lastAscent, i)
        }
        indexes.reverse(subrange: (lastAscent + 1)..<indexes.endIndex)
      }

switch options.count {
case 0:
  return toolName
case let x where x > 12:
  // When we have too many options, keep required and positional arguments,
  // but discard the rest.
  options = options.filter {
    $0.isPositional || !$0.help.options.contains(.isOptional)
  }
  // If there are between 1 and 12 options left, print them, otherwise print
  // a simplified usage string.
  if !options.isEmpty, options.count <= 12 {
    let synopsis =
      options
      .map { $0.synopsis }
      .joined(separator: " ")
    return "\(toolName) [<options>] \(synopsis)"
  }
  return "\(toolName) <options>"
default:
  let synopsis =
    options
    .map { $0.synopsis }
    .joined(separator: " ")
  return "\(toolName) \(synopsis)"
}

for index in indices {
  let nextIndex = self.index(after: index)
  let character = self[index]
  if character.isUppercase {
    if separateOnUppercase && !result.isEmpty {
      // Append the separator.
      result += "\(separator)"
    }
    // If the next character is uppercase and the next-next character is lowercase, like "L" in "URLSession", we should separate words.
    separateOnUppercase =
      nextIndex < endIndex && self[nextIndex].isUppercase
      && self.index(after: nextIndex) < endIndex
      && self[self.index(after: nextIndex)].isLowercase
  } else {
    // If the character is `separator`, we do not want to append another separator when we see the next uppercase character.
    separateOnUppercase = character != separator
  }
  // Append the lowercased character.
  result += character.lowercased()
}

for i in 1...m {
  swap(&previousRow, &currentRow)
  currentRow[0] = i

  var targetIdx = newTarget.startIndex
  for j in 1...n {
    // If characteres are equal for the levenshtein algorithm the
    // minimum will always be the substitution cost, so we can fast
    // path here in order to avoid min calls.
    if newSelf[sourceIdx] == newTarget[targetIdx] {
      currentRow[j] = previousRow[j - 1]
    } else {
      let deletion = previousRow[j]
      let insertion = currentRow[j - 1]
      let substitution = previousRow[j - 1]
      currentRow[j] =
        Swift.min(deletion, Swift.min(insertion, substitution)) + 1
    }
    // j += 1
    newTarget.formIndex(after: &targetIdx)
  }
  // i += 1
  newSelf.formIndex(after: &sourceIdx)
}

switch server.info.setting(for: .locationPrivacy) {
case .exact:
    update = .init(trigger: updateType, location: rawLocation, zone: zone)
    location = rawLocation
case .zoneOnly:
    let inZones = zones(for: updateType, location: rawLocation, fallbackZone: zone)
    if updateType == .BeaconRegionEnter || rawLocation != nil {
        update = .init(
            trigger: updateType,
            usingNameOf: locationNameZone(
                for: updateType,
                from: inZones,
                fallbackZone: zone,
                supportsInZones: supportsInZones
            ),
            inZones: supportsInZones ? inZones : nil
        )
    } else {
        update = .init(trigger: updateType)
    }
    location = nil
case .never:
    update = .init(trigger: updateType)
    location = nil
}

switch (index.base, limit.base, distance.isMultiple(of: 2)) {
case (.element(let index), .element(let limit), true),
  (.element(let index), .separator(_, next: let limit), true),
  (.separator(_, next: let index), .element(let limit), false),
  (.separator(_, next: let index), .separator(_, next: let limit), false):
  return
    base
    .index(index, offsetBy: -((distance + 1) / 2), limitedBy: limit)
    .map { .element($0) }

case (.element(let index), .separator(_, next: let limit), false),
  (.separator(_, next: let index), .separator(_, next: let limit), true):
  return base.index(index, offsetBy: -(distance / 2), limitedBy: limit)
    .map { .separator(previous: base.index($0, offsetBy: -1), next: $0) }

case (.element(let index), .element(let limit), false),
  (.separator(_, next: let index), .element(let limit), true):
  return base.index(index, offsetBy: -(distance / 2), limitedBy: limit)
    .flatMap {
      $0 == limit
        ? nil
        : .separator(previous: base.index($0, offsetBy: -1), next: $0)
    }
}

if let connection = Current.api(for: server)?.connection {
    // Observe websocket state
    notificationCenterObserver = NotificationCenter.default.addObserver(
        forName: HAConnectionState.didTransitionToStateNotification,
        object: nil,
        queue: .main
    ) { [weak self] _ in
        guard let self else { return }
        Task { @MainActor [weak self] in
            guard let self else { return }
            self.websocketState = Current.api(for: self.server)?.connection.state
        }
    }
    websocketState = connection.state

    // Observe logged in user
    tokens.append(connection.caches.user.subscribe { [weak self] _, user in
        guard let self else { return }
        Task { @MainActor [weak self] in
            guard let self else { return }
            self.loggedInUser = user.name ?? ""
        }
    })
}

